export const importarExcel = async (
  importarExcelBody: Blob,
  params: ImportarExcelParams,
  options?: RequestInit,
): Promise<ImportacaoResponse> => {
  return customFetch<ImportacaoResponse>(getImportarExcelUrl(params), {
    ...options,
    method: "POST",
    headers: {
      "Content-Type": "application/octet-stream",
      ...options?.headers,
    },
    body: JSON.stringify(importarExcelBody),
  });
};

export const getImportarExcelMutationOptions = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof importarExcel>>,
    TError,
    { data: BodyType<Blob>; params: ImportarExcelParams },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof importarExcel>>,
  TError,
  { data: BodyType<Blob>; params: ImportarExcelParams },
  TContext
> => {
  const mutationKey = ["importarExcel"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof importarExcel>>,
    { data: BodyType<Blob>; params: ImportarExcelParams }
  > = (props) => {
    const { data, params } = props ?? {};

    return importarExcel(data, params, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type ImportarExcelMutationResult = NonNullable<
  Awaited<ReturnType<typeof importarExcel>>
>;
export type ImportarExcelMutationBody = BodyType<Blob>;
